import SwiftUI

struct SongIDView: View {
    @State private var recognizer = MusicRecognizer()

    var body: some View {
        VStack(spacing: 24) {
            if recognizer.isListening {
                ProgressView("Listening...")
                    .font(.title3)
            } else if !recognizer.matchedTitle.isEmpty {
                VStack(spacing: 8) {
                    if let url = recognizer.artworkURL {
                        AsyncImage(url: url) { image in
                            image.resizable().scaledToFit()
                        } placeholder: {
                            Color.gray.opacity(0.3)
                        }
                        .frame(width: 200, height: 200)
                        .clipShape(RoundedRectangle(cornerRadius: 16))
                    }
                    Text(recognizer.matchedTitle)
                        .font(.title2).fontWeight(.bold)
                    Text(recognizer.matchedArtist)
                        .font(.body).foregroundStyle(.secondary)
                }
            } else if recognizer.noMatch {
                Text("No match found. Try again.")
                    .foregroundStyle(.secondary)
            }

            Button(recognizer.matchedTitle.isEmpty ? "Identify Song" : "Try Again") {
                if !recognizer.matchedTitle.isEmpty { recognizer.reset() }
                Task { await recognizer.startRecognition() }
            }
            .buttonStyle(.borderedProminent)
            .disabled(recognizer.isListening)
        }
        .padding()
        .navigationTitle("Song ID")
    }
}
